<div class="focus-panel"><div class="panel-heading"><h2>Docs</h2><div><button>This project</button><button aria-label="New document">+</button></div></div><div class="doc-list">{#each ['Busywork Masterlist', 'Eyeglasses', 'CubeEnv Potential Roadmaps', 'Sweet & Savory', 'Bigger Arabic'] as document}<button>{document}</button>{/each}</div></div>
<style>.focus-panel { display: grid; grid-template-rows: auto 1fr; gap: .8rem; height: 100%; padding: 1.15rem 1rem; } .panel-heading, .panel-heading div { display: flex; align-items: center; justify-content: space-between; gap: .35rem; } h2 { margin: 0; font-size: 1.05rem; } button { padding: .45rem .6rem; border: 1px solid var(--border-custom); border-radius: .35rem; background: var(--bg-elevated); color: var(--text-main); cursor: pointer; font-size: .7rem; } .doc-list { display: grid; align-content: start; gap: .2rem; } .doc-list button { border-color: transparent; background: transparent; text-align: left; }</style>
